/**
 * @param {number[][]} grid
 * @return {number}
 */
function solve(grid) {
    const M = grid.length;
    const N = grid[0].length;

    // DP[i][j] will store a Set of all possible XOR sums reaching cell (i, j).
    // Initialize DP structure: M rows, N columns, each cell holding a Set.
    const DP = Array(M).fill(0).map(() => Array(N).fill(0).map(() => new Set()));

    // Base Case: (0, 0)
    DP[0][0].add(grid[0][0]);

    // Fill first row (i=0)
    for (let j = 1; j < N; j++) {
        const currentValue = grid[0][j];
        for (const prevXor of DP[0][j - 1]) {
            DP[0][j].add(prevXor ^ currentValue);
        }
    }

    // Fill first column (j=0)
    for (let i = 1; i < M; i++) {
        const currentValue = grid[i][0];
        for (const prevXor of DP[i - 1][0]) {
            DP[i][0].add(prevXor ^ currentValue);
        }
    }

    // Fill the rest of the grid
    for (let i = 1; i < M; i++) {
        for (let j = 1; j < N; j++) {
            const currentValue = grid[i][j];

            // From above (i-1, j)
            for (const prevXor of DP[i - 1][j]) {
                DP[i][j].add(prevXor ^ currentValue);
            }

            // From left (i, j-1)
            for (const prevXor of DP[i][j - 1]) {
                DP[i][j].add(prevXor ^ currentValue);
            }
        }
    }

    // Find the minimum XOR sum at the bottom-right corner (M-1, N-1)
    const finalXors = DP[M - 1][N - 1];

    if (finalXors.size === 0) {
        // This should not happen given the constraints, but as a safeguard
        return -1; 
    }

    let minXor = Infinity;
    for (const xorSum of finalXors) {
        if (xorSum < minXor) {
            minXor = xorSum;
        }
    }

    return minXor;
}

