fn solve(grid: Vec<Vec<i64>>) -> i64 {
    let m = grid.len();
    if m == 0 {
        return 0; // Should not happen based on constraints
    }
    let n = grid[0].len();
    if n == 0 {
        return 0; // Should not happen based on constraints
    }

    // Since grid[i][j] <= 1023, the maximum possible XOR sum is 1023.
    // We use a boolean array of size 1024 to represent the set of reachable XOR sums.
    const K: usize = 1024;

    // DP[i][j] stores an array where DP[i][j][x] is true if XOR sum x is reachable at (i, j).
    // We use Vec<Vec<[bool; K]>> to represent the M x N grid of sets.
    let mut dp: Vec<Vec<[bool; K]>> = Vec::with_capacity(m);
    for _ in 0..m {
        let mut row: Vec<[bool; K]> = Vec::with_capacity(n);
        for _ in 0..n {
            row.push([false; K]);
        }
        dp.push(row);
    }

    // Base Case: (0, 0)
    let start_xor = (grid[0][0] & 0xFFF) as usize; // Ensure it fits within K
    dp[0][0][start_xor] = true;

    // Fill the DP table
    for i in 0..m {
        for j in 0..n {
            if i == 0 && j == 0 {
                continue;
            }

            let current_val = (grid[i][j] & 0xFFF) as usize;
            let mut current_dp = dp[i][j];

            // Contribution from above (i-1, j)
            if i > 0 {
                let prev_row = &dp[i - 1];
                for x in 0..K {
                    if prev_row[j][x] {
                        let new_xor = x ^ current_val;
                        current_dp[new_xor] = true;
                    }
                }
            }

            // Contribution from left (i, j-1)
            if j > 0 {
                let prev_col = &dp[i][j - 1];
                for y in 0..K {
                    if prev_col[y] {
                        let new_xor = y ^ current_val;
                        current_dp[new_xor] = true;
                    }
                }
            }

            dp[i][j] = current_dp;
        }
    }

    // Find the minimum XOR sum at the bottom-right corner (m-1, n-1)
    let final_dp = &dp[m - 1][n - 1];

    for x in 0..K {
        if final_dp[x] {
            // Since we iterate in increasing order of x, the first true value is the minimum.
            return x as i64;
        }
    }

    // Should not be reached if constraints are met (M, N >= 1)
    return -1; 
}

